<?php
$pageTitle='KPI Builder';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('kpi_builder');
$pdo=getDB();
$sources=['revenue_mtd'=>'Revenue MTD','orders_mtd'=>'Orders MTD','open_ar'=>'Open Receivables','low_stock'=>'Low Stock Items','open_approvals'=>'Open Approvals','open_pipeline'=>'Open Sales Pipeline','payroll_exposure'=>'Payroll Exposure'];
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'');
    if($action==='create_kpi'){
      $code=preg_replace('/[^A-Z0-9_\\-]/','',strtoupper((string)$_POST['kpi_code']));
      $stmt=$pdo->prepare('INSERT INTO '.table('report_kpis').' (kpi_code,kpi_name,kpi_group,metric_source,calculation_type,target_value,warning_value,unit_label,sort_order,active) VALUES (?,?,?,?,?,?,?,?,?,1)');
      $stmt->execute([$code,trim((string)$_POST['kpi_name']),trim((string)$_POST['kpi_group']),trim((string)$_POST['metric_source']),trim((string)$_POST['calculation_type']),max(0,(float)$_POST['target_value']),max(0,(float)$_POST['warning_value']),trim((string)$_POST['unit_label']),(int)$_POST['sort_order']]);flash('success','KPI created.');
    }elseif($action==='snapshot'){$result=snapshotAllKpis($pdo,trim((string)($_POST['snapshot_date']??date('Y-m-d')))?:date('Y-m-d'));flash('success','KPI snapshot created for '.$result['count'].' KPIs.');}
    elseif($action==='toggle'){$pdo->prepare('UPDATE '.table('report_kpis').' SET active=CASE WHEN active=1 THEN 0 ELSE 1 END WHERE id=?')->execute([(int)$_POST['id']]);flash('success','KPI status changed.');}
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'kpi-builder']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/kpi-builder.php');
}
$kpis=$pdo->query('SELECT * FROM '.table('report_kpis').' ORDER BY active DESC,sort_order,kpi_name')->fetchAll();
$snapshots=$pdo->query('SELECT s.*,k.kpi_code,k.kpi_name FROM '.table('kpi_snapshots').' s LEFT JOIN '.table('report_kpis').' k ON k.id=s.report_kpi_id ORDER BY s.snapshot_date DESC,s.created_at DESC LIMIT 120')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">KPI Engine</div><h2 class="h4 mb-1">KPI Builder</h2><p class="text-secondary mb-0">Define KPIs, set targets, and capture daily KPI snapshots.</p></div><form method="post"><input type="hidden" name="action" value="snapshot"><input type="hidden" name="snapshot_date" value="<?php echo esc(date('Y-m-d')); ?>"><button class="btn btn-brand">Snapshot Today</button></form></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="create_kpi"><h2 class="h5 mb-3">Create KPI</h2><input class="form-control mb-2" name="kpi_code" placeholder="KPI-CODE" required><input class="form-control mb-2" name="kpi_name" placeholder="KPI name" required><input class="form-control mb-2" name="kpi_group" value="Management"><label class="form-label">Metric Source</label><select class="form-select mb-2" name="metric_source"><?php foreach($sources as $key=>$label): ?><option value="<?php echo esc($key); ?>"><?php echo esc($label); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="calculation_type"><option value="sum">Sum</option><option value="count">Count</option><option value="ratio">Ratio</option></select><div class="row g-2"><div class="col-6"><input class="form-control" type="number" step="0.01" name="target_value" placeholder="Target"></div><div class="col-6"><input class="form-control" type="number" step="0.01" name="warning_value" placeholder="Warning"></div></div><input class="form-control my-2" name="unit_label" placeholder="AED / items / %"><input class="form-control mb-3" type="number" name="sort_order" value="100"><button class="btn btn-brand w-100">Create KPI</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">KPI Definitions</h2><table class="table align-middle"><thead><tr><th>KPI</th><th>Source</th><th>Current</th><th>Target</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($kpis as $kpi): $value=kpiMetricValue($pdo,(string)$kpi['metric_source']); $status=((float)$kpi['target_value']>0 && $value<(float)$kpi['target_value'])?'below_target':'above_target'; ?><tr><td><strong><?php echo esc($kpi['kpi_code']); ?></strong><div class="small text-secondary"><?php echo esc($kpi['kpi_name'].' · '.$kpi['kpi_group']); ?></div></td><td><?php echo esc($sources[$kpi['metric_source']]??$kpi['metric_source']); ?></td><td><?php echo number_format((float)$value,2).' '.esc($kpi['unit_label']); ?></td><td><?php echo number_format((float)$kpi['target_value'],2); ?></td><td><span class="badge bg-<?php echo esc(statusTone($status)); ?>"><?php echo esc($status); ?></span></td><td><form method="post"><input type="hidden" name="action" value="toggle"><input type="hidden" name="id" value="<?php echo (int)$kpi['id']; ?>"><button class="btn btn-sm btn-outline-secondary"><?php echo $kpi['active']?'Disable':'Enable'; ?></button></form></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Recent Snapshots</h2><table class="table"><thead><tr><th>Date</th><th>KPI</th><th>Value</th><th>Target</th><th>Status</th></tr></thead><tbody><?php foreach($snapshots as $s): ?><tr><td><?php echo esc($s['snapshot_date']); ?></td><td><?php echo esc($s['kpi_code'].' · '.$s['kpi_name']); ?></td><td><?php echo number_format((float)$s['metric_value'],2); ?></td><td><?php echo number_format((float)$s['target_value'],2); ?></td><td><span class="badge bg-<?php echo esc(statusTone($s['status'])); ?>"><?php echo esc($s['status']); ?></span></td></tr><?php endforeach; ?><?php if(!$snapshots): ?><tr><td colspan="5" class="text-secondary">No KPI snapshots yet.</td></tr><?php endif; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>